CREATE DATABASE IF NOT EXISTS reflexshowdown CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE reflexshowdown;
CREATE TABLE IF NOT EXISTS players (player_id INT NOT NULL AUTO_INCREMENT, username VARCHAR(50) NOT NULL, password_hash VARCHAR(255) NOT NULL DEFAULT '', total_games INT NOT NULL DEFAULT 0, total_wins INT NOT NULL DEFAULT 0, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (player_id), UNIQUE KEY uk_username (username)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS game_sessions (session_id INT NOT NULL AUTO_INCREMENT, room_code VARCHAR(8) NOT NULL, winner_player_id INT NULL, started_at DATETIME NOT NULL, ended_at DATETIME NULL, PRIMARY KEY (session_id), KEY idx_room (room_code), CONSTRAINT fk_sess_winner FOREIGN KEY (winner_player_id) REFERENCES players (player_id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS rounds (round_id INT NOT NULL AUTO_INCREMENT, session_id INT NOT NULL, round_number TINYINT NOT NULL, signal_time BIGINT NOT NULL, PRIMARY KEY (round_id), KEY idx_sess (session_id), CONSTRAINT fk_rnd_sess FOREIGN KEY (session_id) REFERENCES game_sessions (session_id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS round_results (result_id INT NOT NULL AUTO_INCREMENT, round_id INT NOT NULL, player_id INT NOT NULL, click_time BIGINT NOT NULL, reaction_time_ms INT NOT NULL, is_early_click TINYINT(1) NOT NULL DEFAULT 0, rank_in_round TINYINT NOT NULL, points_earned TINYINT NOT NULL DEFAULT 0, PRIMARY KEY (result_id), KEY idx_round (round_id), KEY idx_player (player_id), CONSTRAINT fk_res_round FOREIGN KEY (round_id) REFERENCES rounds (round_id) ON DELETE CASCADE, CONSTRAINT fk_res_player FOREIGN KEY (player_id) REFERENCES players (player_id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
